-- Ontario 2026 NAMED-WATER-BODY EXCEPTIONS  (state = 'ON', lake-scoped)
-- Companion to script11_regulations_ontario2026.sql (zone-wide rules).
-- Source: https://www.ontario.ca/document/ontario-fishing-regulations-summary
--         (per-FMZ 'Waterbody exceptions' sections)
--
-- PROVENANCE: reverse-engineered from PROD (DB_111487_fish), refreshed 2026-07-09
-- after loading the FMZ 5 (Lake of the Woods, Wabigoon) + FMZ 6 (Arrow River)
-- exceptions. 147 rows / 57 named waters.
-- Lake-scoped: Lake_id set, zone_id NULL, reg_year 2026. fish_id resolved by
-- fish_name for cross-node portability; Lake_id = literal GUID.
--
-- Idempotent: deletes ALL ON/2026 lake-scoped rows, then re-inserts this set (single
-- source of truth). NOT part of ffi2.sql (standalone, applied manually like script11).
---------------------------------------------------------------------------------
SET NOCOUNT ON;
DECLARE @yr smallint = 2026;
DELETE FROM dbo.regulations WHERE state='ON' AND reg_year=@yr AND zone_id IS NULL AND Lake_id IS NOT NULL;
GO

